function checkBox(){let e=document.querySelectorAll(".check-accept"),t=document.querySelectorAll(".check__checkbox-accept");if(e.length>0)for(let c=0;c<e.length;c++){e[c].checked&&t.classList.add("active")}for(let e=0;e<t.length;e++){t[e].addEventListener("click",(function(e){e.preventDefault,this.classList.contains("active")?this.querySelector(".check-accept").checked=!1:this.querySelector(".check-accept").checked=!0,this.classList.toggle("active")}))}}checkBox(),$(document).ready((function(){$(".acord__top").click((function(e){e.preventDefault(),$(".acord").hasClass("one-acord")&&($(".acord__top").not($(this)).removeClass("active__acord"),$(".acord__bot").not($(this).next()).slideUp(300)),$(this).toggleClass("active__acord").next().slideToggle(300)})),$(".more__settings-body").click((function(e){e.preventDefault(),$(".direction").slideToggle(300)}))})),document.querySelector(".more__settings-body").addEventListener("click",()=>{document.querySelector(".more__settings-body").classList.toggle("open-settings")}),document.querySelectorAll(".input__range-block").forEach(e=>{const t=e.querySelector(".range__input"),c=e.querySelector(".r-num");c.innerHTML=t.value;const n=e.querySelector(".min-score");n.innerHTML=80,n.style.left=100*n.innerHTML/200+"%",t.addEventListener("input",()=>{let e=t.value;e=100*e/200,t.style.background="-webkit-linear-gradient(left, #05396a 0%, #05396a "+e+"%, #fff "+e+"%, #fff 100%)",t.style.background="-moz-linear-gradient(left, #05396a 0%, #05396a "+e+"%, #fff "+e+"%, #fff 100%)",c.innerHTML=t.value,c.style.left=e+"%",c.style.transform="translate(-"+e+"%, 0%)",+t.value>=+n.innerHTML?n.style.display="none":n.style.display="block"})}),window.innerWidth<=700&&$("#dbt1").click((function(e){e.preventDefault(),$(this).toggleClass("active"),$(".direction__body-inner").slideToggle()})),window.innerWidth<=700&&$("#dbt2").click((function(e){e.preventDefault(),$(this).toggleClass("active"),$(".direction__filters-body").slideToggle()}));